import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import Timer from './Timer';

const QuizPage = ({ quizId, teamInfo, onSubmit, onTimeout }) => {
  const [questions, setQuestions] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [answers, setAnswers] = useState({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [tabSwitchCount, setTabSwitchCount] = useState(0);
  const [submitting, setSubmitting] = useState(false);

  // Anti-screenshot and copy protection
  useEffect(() => {
    const preventAll = (e) => {
      e.preventDefault();
      e.stopPropagation();
      return false;
    };

    const blockKeys = (e) => {
      if (
        e.ctrlKey || e.metaKey || e.altKey || 
        e.key === 'PrintScreen' ||
        e.key === 'F12'
      ) {
        e.preventDefault();
        return false;
      }

      if (e.ctrlKey || e.metaKey) {
        e.preventDefault();
        return false;
      }
    };

    document.addEventListener('contextmenu', preventAll);
    document.addEventListener('copy', preventAll);
    document.addEventListener('cut', preventAll);
    document.addEventListener('paste', preventAll);
    document.addEventListener('selectstart', preventAll);
    document.addEventListener('keydown', blockKeys);

    const style = document.createElement('style');
    style.innerHTML = `
      * {
        -webkit-user-select: none !important;
        -moz-user-select: none !important;
        -ms-user-select: none !important;
        user-select: none !important;
      }
    `;
    document.head.appendChild(style);

    return () => {
      document.removeEventListener('contextmenu', preventAll);
      document.removeEventListener('copy', preventAll);
      document.removeEventListener('cut', preventAll);
      document.removeEventListener('paste', preventAll);
      document.removeEventListener('selectstart', preventAll);
      document.removeEventListener('keydown', blockKeys);
      document.head.removeChild(style);
    };
  }, []);

  // Tab switch detection
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.hidden && !submitting && !loading) {
        setTabSwitchCount(prev => {
          const newCount = prev + 1;

          if (newCount === 1) {
            alert('⚠️ Warning: Tab switching is not allowed. One more violation will end your quiz.');
          }

          if (newCount >= 2) {
            alert('❌ Quiz ended due to tab switching violation. Submitting your answers...');
            setTimeout(() => handleSubmitQuiz(), 500);
          }

          return newCount;
        });
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => document.removeEventListener('visibilitychange', handleVisibilityChange);
  }, [submitting, loading]);

  // Prevent back navigation
  useEffect(() => {
    window.history.pushState(null, null, window.location.href);
    const handlePopState = () => {
      window.history.pushState(null, null, window.location.href);
      alert('⛔ Navigation is disabled during quiz');
    };

    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  // Fetch questions
  useEffect(() => {
    const fetchQuestions = async () => {
      try {
        setLoading(true);
        setError('');

        if (!quizId) {
          setError('No quiz ID provided');
          setLoading(false);
          return;
        }

        const response = await axios.get(`http://localhost:8000/questions/${quizId}`);
        console.log('Questions response:', response.data);

        if (response.data && response.data.questions && response.data.questions.length > 0) {
          setQuestions(response.data.questions);
          // Initialize answers
          const initialAnswers = {};
          response.data.questions.forEach(q => {
            initialAnswers[q.id] = null;
          });
          setAnswers(initialAnswers);
          setCurrentIndex(0);
        } else {
          setError('No questions available');
        }
      } catch (err) {
        console.error('Fetch error:', err);
        if (err.code === 'ERR_NETWORK') {
          setError('Cannot connect to server. Please check if backend is running.');
        } else if (err.response) {
          if (err.response.status === 404) {
            setError('Quiz session not found. Please start a new quiz.');
          } else {
            setError(`Server error: ${err.response.data?.detail || 'Unknown error'}`);
          }
        } else {
          setError('Failed to load questions. Please try again.');
        }
      } finally {
        setLoading(false);
      }
    };

    fetchQuestions();
  }, [quizId]);

  const handleSubmitQuiz = useCallback(async () => {
    if (submitting) return;

    const answeredQuestions = Object.entries(answers).filter(([_, value]) => value !== null);

    if (answeredQuestions.length !== questions.length) {
      alert(`Please answer all questions. You have answered ${answeredQuestions.length} out of ${questions.length} questions.`);
      return;
    }

    setSubmitting(true);

    try {
      const answersList = answeredQuestions.map(([qId, selected]) => ({
        question_id: parseInt(qId),
        selected_option: selected
      }));

      console.log('Submitting answers:', answersList);

      const response = await axios.post('http://localhost:8000/submit', {
        quiz_id: quizId,
        answers: answersList,
        tab_switch_count: tabSwitchCount
      });

      console.log('Submission response:', response.data);

      if (response.data && response.data.score !== undefined) {
        // Pass both answers and questions to result page
        onSubmit({
          score: response.data.score,
          totalQuestions: response.data.total_questions,
          timeTaken: response.data.time_taken_microseconds,
          answers: answers,
          questions: questions
        });
      }

    } catch (err) {
      console.error('Submission error:', err);

      let errorMessage = 'Failed to submit. ';

      if (err.response) {
        if (err.response.data && err.response.data.detail) {
          errorMessage += err.response.data.detail;
        } else {
          errorMessage += 'Server error. Please try again.';
        }
      } else if (err.request) {
        errorMessage += 'Cannot connect to server. Please check if backend is running.';
      } else {
        errorMessage += err.message;
      }

      alert(errorMessage);
      setSubmitting(false);
    }
  }, [quizId, answers, tabSwitchCount, onSubmit, submitting, questions]);

  const handleAnswerSelect = (questionId, option) => {
    if (submitting) return;

    setAnswers(prev => ({
      ...prev,
      [questionId]: option
    }));

    if (currentIndex < questions.length - 1) {
      setTimeout(() => {
        setCurrentIndex(prev => prev + 1);
      }, 300);
    }
  };

  const goToQuestion = (index) => {
    if (index >= 0 && index < questions.length) {
      setCurrentIndex(index);
    }
  };

  const handleSubmit = () => {
    handleSubmitQuiz();
  };

  const handleTimeUp = () => {
    if (!submitting) {
      const answeredCount = Object.values(answers).filter(v => v !== null).length;
      if (answeredCount > 0) {
        alert('⏰ Time is up! Submitting your answers...');
        handleSubmitQuiz();
        if (onTimeout) onTimeout();
      }
    }
  };

  if (loading) {
    return (
      <div style={{
        height: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        backgroundColor: '#ffffff',
        color: '#333333',
        fontSize: '18px'
      }}>
        Loading questions...
      </div>
    );
  }

  if (error) {
    return (
      <div style={{
        height: '100vh',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        backgroundColor: '#ffffff',
        padding: '20px'
      }}>
        <h2 style={{ color: '#ff0000', marginBottom: '20px' }}>Error</h2>
        <p style={{ color: '#333333', marginBottom: '30px', textAlign: 'center' }}>{error}</p>
        <button 
          onClick={() => window.location.href = '/'}
          style={{
            padding: '12px 30px',
            backgroundColor: '#000000',
            color: '#ffffff',
            border: 'none',
            borderRadius: '4px',
            fontSize: '16px',
            cursor: 'pointer'
          }}
        >
          Go to Start
        </button>
      </div>
    );
  }

  if (!questions || questions.length === 0) {
    return (
      <div style={{
        height: '100vh',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        backgroundColor: '#ffffff'
      }}>
        <h2 style={{ color: '#ff0000', marginBottom: '20px' }}>No Questions Available</h2>
        <button 
          onClick={() => window.location.href = '/'}
          style={{
            padding: '12px 30px',
            backgroundColor: '#000000',
            color: '#ffffff',
            border: 'none',
            borderRadius: '4px',
            fontSize: '16px',
            cursor: 'pointer'
          }}
        >
          Go to Start
        </button>
      </div>
    );
  }

  const currentQuestion = questions[currentIndex];

  if (!currentQuestion) {
    return (
      <div style={{
        height: '100vh',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        backgroundColor: '#ffffff'
      }}>
        <h2 style={{ color: '#ff0000', marginBottom: '20px' }}>Error Loading Question</h2>
        <button 
          onClick={() => window.location.reload()}
          style={{
            padding: '12px 30px',
            backgroundColor: '#000000',
            color: '#ffffff',
            border: 'none',
            borderRadius: '4px',
            fontSize: '16px',
            cursor: 'pointer',
            marginRight: '10px'
          }}
        >
          Reload
        </button>
        <button 
          onClick={() => window.location.href = '/'}
          style={{
            padding: '12px 30px',
            backgroundColor: '#666666',
            color: '#ffffff',
            border: 'none',
            borderRadius: '4px',
            fontSize: '16px',
            cursor: 'pointer',
            marginTop: '10px'
          }}
        >
          Go to Start
        </button>
      </div>
    );
  }

  const answeredCount = Object.values(answers).filter(v => v !== null).length;
  const remainingCount = questions.length - answeredCount;
  const allAnswered = answeredCount === questions.length;

  return (
    <div style={{
      minHeight: '100vh',
      backgroundColor: '#ffffff',
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center'
    }}>
      <div style={{
        width: '100%',
        maxWidth: '700px',
        padding: '40px 20px'
      }}>
        {/* Header */}
        <div style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: '20px',
          paddingBottom: '15px',
          borderBottom: '1px solid #e5e5e5'
        }}>
          <div style={{ 
            fontSize: '18px',
            fontWeight: '500',
            color: '#333333'
          }}>
            Question {currentIndex + 1} of {questions.length}
          </div>
          <Timer 
            initialSeconds={1800}
            onTimeUp={handleTimeUp}
            isActive={!submitting}
          />
        </div>

        {/* Question navigation */}
        <div style={{
          display: 'flex',
          gap: '8px',
          marginBottom: '30px',
          flexWrap: 'wrap',
          justifyContent: 'center'
        }}>
          {questions.map((q, idx) => {
            const isAnswered = answers[q.id] !== null;
            const isCurrent = idx === currentIndex;

            return (
              <div
                key={q.id}
                onClick={() => goToQuestion(idx)}
                style={{
                  width: '32px',
                  height: '32px',
                  borderRadius: '16px',
                  backgroundColor: isAnswered ? '#000000' : '#e0e0e0',
                  border: isCurrent ? '3px solid #ff0000' : 'none',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  color: isAnswered ? '#ffffff' : '#666666',
                  fontSize: '13px',
                  fontWeight: '600',
                  cursor: 'pointer'
                }}
              >
                {idx + 1}
              </div>
            );
          })}
        </div>

        {/* Warning */}
        {tabSwitchCount === 1 && (
          <div style={{
            backgroundColor: '#fff3cd',
            color: '#856404',
            padding: '12px 16px',
            marginBottom: '30px',
            fontSize: '14px',
            borderRadius: '4px'
          }}>
            ⚠️ Warning: Tab switching detected (1/2)
          </div>
        )}

        {/* Question */}
        <div style={{ marginBottom: '40px' }}>
          <h2 style={{
            fontSize: '22px',
            fontWeight: '500',
            lineHeight: '1.6',
            marginBottom: '30px',
            color: '#000000'
          }}>
            {currentQuestion.question}
          </h2>

          {/* Options */}
          <div>
            {currentQuestion.options.map((option, idx) => {
              const isSelected = answers[currentQuestion.id] === option;
              const optionId = `opt_${currentQuestion.id}_${idx}`;

              return (
                <div
                  key={idx}
                  onClick={() => !submitting && handleAnswerSelect(currentQuestion.id, option)}
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    marginBottom: '16px',
                    cursor: submitting ? 'default' : 'pointer',
                    padding: '12px 16px',
                    backgroundColor: isSelected ? '#f0f0f0' : 'transparent',
                    borderRadius: '8px',
                    border: isSelected ? '2px solid #000000' : '1px solid #e0e0e0'
                  }}
                >
                  <input
                    type="radio"
                    id={optionId}
                    name={`q_${currentQuestion.id}`}
                    checked={isSelected}
                    onChange={() => {}}
                    disabled={submitting}
                    style={{
                      width: '20px',
                      height: '20px',
                      marginRight: '15px',
                      cursor: submitting ? 'default' : 'pointer',
                      accentColor: '#000000'
                    }}
                  />
                  <label
                    htmlFor={optionId}
                    style={{
                      fontSize: '16px',
                      cursor: submitting ? 'default' : 'pointer',
                      color: '#333333',
                      fontWeight: isSelected ? '600' : '400'
                    }}
                  >
                    {option}
                  </label>
                </div>
              );
            })}
          </div>
        </div>

        {/* Progress */}
        <div style={{
          marginBottom: '25px',
          padding: '15px',
          backgroundColor: '#f8f8f8',
          borderRadius: '8px'
        }}>
          <div style={{
            display: 'flex',
            justifyContent: 'space-between',
            marginBottom: '10px'
          }}>
            <span>Progress: {answeredCount}/{questions.length}</span>
            <span style={{ color: remainingCount === 0 ? '#00aa00' : '#ff0000' }}>
              {remainingCount === 0 ? '✓ COMPLETE' : `${remainingCount} remaining`}
            </span>
          </div>
          <div style={{
            width: '100%',
            height: '8px',
            backgroundColor: '#e0e0e0',
            borderRadius: '4px',
            overflow: 'hidden'
          }}>
            <div style={{
              width: `${(answeredCount / questions.length) * 100}%`,
              height: '100%',
              backgroundColor: remainingCount === 0 ? '#00aa00' : '#000000'
            }} />
          </div>
        </div>

        {/* Submit button */}
        <button
          onClick={handleSubmit}
          disabled={!allAnswered || submitting}
          style={{
            width: '100%',
            backgroundColor: !allAnswered ? '#cccccc' : (submitting ? '#999999' : '#000000'),
            color: '#ffffff',
            border: 'none',
            padding: '18px 0',
            borderRadius: '8px',
            fontSize: '18px',
            fontWeight: '600',
            cursor: (!allAnswered || submitting) ? 'not-allowed' : 'pointer',
            opacity: (!allAnswered || submitting) ? 0.7 : 1
          }}
        >
          {submitting ? 'SUBMITTING...' : 'SUBMIT QUIZ'}
        </button>
      </div>
    </div>
  );
};

export default QuizPage;
